import item from './items.json'
export default {
  name: 'new',
  data () {
    return {
      saleShow: false,
      topShow: false,
      bottomShow: false,
      onePieceShow: false,
      homeWearShow: false,
      accessoryShow: false,
      items: item
    }
  }
}
